// menu.js - عند الضغط على الكارد يكبر ويعرض جميع المنتجات
import { useState, useEffect } from "react";

export default function Menu() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [textIndex, setTextIndex] = useState(0);
  const [selectedCard, setSelectedCard] = useState(null); // الكارد المختار
  const [showProducts, setShowProducts] = useState(false); // عرض المنتجات
  
  const backgroundImageUrl = "https://img.freepik.com/photos-premium/banniere-pour-page-menu-table-cuisine-legumes-epices-ustensiles-fond-sombre-vue-dessus-espace-libre-pour-texte_187166-66331.jpg?semt=ais_hybrid&w=740&q=80";
  
  const texts = ["مرحباً", "أهلاً", "تفضلوا", "استمتعوا"];

  // الكاردات الرئيسية
  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", size: 200, top: "15%", left: "10%", rotate: -6, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
    { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", size: 190, bottom: "15%", left: "12%", rotate: 4, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", size: 195, top: "18%", right: "10%", rotate: -4, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
    { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", size: 185, bottom: "18%", right: "12%", rotate: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" }
  ];

  // المنتجات لكل قسم
  const productsByCard = {
    1: [ // شيشة
      { id: 101, name: "شيشة تفاح", price: "15 دينار", icon: "🍎", image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
      { id: 102, name: "شيشة عنب", price: "15 دينار", icon: "🍇", image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
      { id: 103, name: "شيشة نعناع", price: "15 دينار", icon: "🌿", image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
      { id: 104, name: "شيشة مانجو", price: "18 دينار", icon: "🥭", image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" }
    ],
    2: [ // أكل
      { id: 201, name: "برغر", price: "12 دينار", icon: "🍔", image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
      { id: 202, name: "بيتزا", price: "18 دينار", icon: "🍕", image: "https://cdn-icons-png.flaticon.com/512/1046/1046796.png" },
      { id: 203, name: "ساندويش", price: "8 دينار", icon: "🥪", image: "https://cdn-icons-png.flaticon.com/512/1046/1046788.png" },
      { id: 204, name: "سلطة", price: "6 دينار", icon: "🥗", image: "https://cdn-icons-png.flaticon.com/512/1046/1046792.png" }
    ],
    3: [ // مشروبات
      { id: 301, name: "كولا", price: "3 دينار", icon: "🥤", image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
      { id: 302, name: "عصير برتقال", price: "5 دينار", icon: "🍊", image: "https://cdn-icons-png.flaticon.com/512/1046/1046874.png" },
      { id: 303, name: "عصير ليمون", price: "4 دينار", icon: "🍋", image: "https://cdn-icons-png.flaticon.com/512/1046/1046874.png" },
      { id: 304, name: "ماء", price: "2 دينار", icon: "💧", image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" }
    ],
    4: [ // ديسار
      { id: 401, name: "كيك", price: "7 دينار", icon: "🍰", image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" },
      { id: 402, name: "آيس كريم", price: "5 دينار", icon: "🍦", image: "https://cdn-icons-png.flaticon.com/512/1046/1046800.png" },
      { id: 403, name: "كنافة", price: "8 دينار", icon: "🍯", image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" },
      { id: 404, name: "فواكه", price: "6 دينار", icon: "🍉", image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" }
    ]
  };

  useEffect(() => {
    const interval = setInterval(() => {
      if (!showProducts) {
        setTextIndex((prev) => (prev + 1) % texts.length);
      }
    }, 2500);
    return () => clearInterval(interval);
  }, [showProducts]);

  useEffect(() => {
    const handleMouseMove = (e) => {
      if (!showProducts) {
        setMousePosition({
          x: (e.clientX / window.innerWidth - 0.5) * 40,
          y: (e.clientY / window.innerHeight - 0.5) * 40
        });
      }
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, [showProducts]);

  const handleCardClick = (card) => {
    setSelectedCard(card);
    setShowProducts(true);
  };

  const handleCloseProducts = () => {
    setShowProducts(false);
    setSelectedCard(null);
  };

  return (
    <div style={{
      minHeight: "100vh",
      backgroundImage: `url(${backgroundImageUrl})`,
      backgroundSize: "cover",
      backgroundPosition: "center",
      backgroundRepeat: "no-repeat",
      backgroundAttachment: "fixed",
      position: "relative",
      overflow: "hidden",
      fontFamily: "sans-serif"
    }}>
      
      {/* طبقة داكنة عند عرض المنتجات */}
      {showProducts && (
        <div style={{
          position: "fixed",
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: "rgba(0,0,0,0.85)",
          zIndex: 40,
          animation: "fadeIn 0.3s ease"
        }} onClick={handleCloseProducts}></div>
      )}

      {/* نافذة عرض المنتجات الموسعة */}
      {showProducts && selectedCard && (
        <div style={{
          position: "fixed",
          top: "50%",
          left: "50%",
          transform: "translate(-50%, -50%)",
          width: "80%",
          maxWidth: "900px",
          maxHeight: "80vh",
          background: `linear-gradient(135deg, ${selectedCard.color}, ${selectedCard.color}dd)`,
          borderRadius: "40px",
          padding: "30px",
          zIndex: 50,
          animation: "zoomIn 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)",
          overflowY: "auto",
          boxShadow: "0 30px 60px rgba(0,0,0,0.5), 0 0 0 4px rgba(255,255,255,0.3)"
        }}>
          <button onClick={handleCloseProducts} style={{
            position: "absolute",
            top: "20px",
            right: "25px",
            background: "rgba(0,0,0,0.5)",
            border: "none",
            color: "white",
            fontSize: "24px",
            cursor: "pointer",
            width: "40px",
            height: "40px",
            borderRadius: "50%",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            transition: "all 0.3s"
          }} onMouseEnter={(e) => e.currentTarget.style.background = "#ff4444"} onMouseLeave={(e) => e.currentTarget.style.background = "rgba(0,0,0,0.5)"}>✕</button>
          
          <div style={{ textAlign: "center", marginBottom: "30px" }}>
            <span style={{ fontSize: "5rem" }}>{selectedCard.icon}</span>
            <h2 style={{ color: "white", fontSize: "2.5rem", margin: "10px 0", fontWeight: "bold" }}>{selectedCard.name}</h2>
            <div style={{ width: "80px", height: "3px", background: "white", margin: "10px auto" }}></div>
          </div>

          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
            gap: "20px"
          }}>
            {productsByCard[selectedCard.id]?.map((product) => (
              <div key={product.id} style={{
                background: "rgba(255,255,255,0.15)",
                backdropFilter: "blur(10px)",
                borderRadius: "25px",
                padding: "20px",
                textAlign: "center",
                transition: "all 0.3s",
                cursor: "pointer",
                border: "1px solid rgba(255,255,255,0.3)"
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = "scale(1.05)";
                e.currentTarget.style.background = "rgba(255,255,255,0.25)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = "scale(1)";
                e.currentTarget.style.background = "rgba(255,255,255,0.15)";
              }}
              onClick={() => alert(`✨ تم إضافة ${product.name} إلى السلة بسعر ${product.price} ✨`)}>
                <img src={product.image} alt={product.name} style={{ width: "70px", height: "70px", marginBottom: "10px" }} />
                <h3 style={{ color: "white", fontSize: "1.3rem", margin: "10px 0" }}>{product.name}</h3>
                <p style={{ color: "#22c55e", fontSize: "1.2rem", fontWeight: "bold" }}>{product.price}</p>
                <span style={{ fontSize: "2rem" }}>{product.icon}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes zoomIn {
          from { 
            opacity: 0;
            transform: translate(-50%, -50%) scale(0.8);
          }
          to { 
            opacity: 1;
            transform: translate(-50%, -50%) scale(1);
          }
        }
      `}</style>

      {/* الكاردات - تختفي عند عرض المنتجات */}
      {!showProducts && cards.map((card) => (
        <div
          key={card.id}
          onClick={() => handleCardClick(card)}
          style={{
            position: "fixed",
            top: card.top,
            left: card.left,
            right: card.right,
            bottom: card.bottom,
            transform: `
              translate(
                ${mousePosition.x * (card.id % 2 === 0 ? 0.6 : -0.5)}px, 
                ${mousePosition.y * (card.id % 2 === 0 ? -0.5 : 0.6)}px
              ) 
              rotate(${card.rotate}deg)
            `,
            transition: "transform 0.2s ease-out",
            zIndex: 15,
            cursor: "pointer"
          }}
        >
          <div style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}cc)`,
            width: `${card.size}px`,
            padding: "30px 18px",
            borderRadius: "40px",
            textAlign: "center",
            boxShadow: "0 25px 50px rgba(0,0,0,0.5)",
            backdropFilter: "blur(8px)",
            border: "2px solid rgba(255,255,255,0.3)",
            transition: "all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = `scale(1.1) rotate(${card.rotate + 8}deg)`;
            e.currentTarget.style.boxShadow = "0 40px 70px rgba(0,0,0,0.6)";
            e.currentTarget.style.border = "2px solid rgba(34,197,94,0.9)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "scale(1) rotate(0deg)";
            e.currentTarget.style.boxShadow = "0 25px 50px rgba(0,0,0,0.5)";
            e.currentTarget.style.border = "2px solid rgba(255,255,255,0.3)";
          }}
          >
            <img 
              src={card.image} 
              alt={card.name} 
              style={{ 
                width: "85px", 
                height: "85px", 
                marginBottom: "12px", 
                filter: "drop-shadow(2px 4px 10px black)" 
              }} 
            />
            <h3 style={{ 
              color: "white", 
              margin: "10px 0 5px", 
              fontSize: "1.8rem", 
              fontWeight: "bold" 
            }}>{card.name}</h3>
            <span style={{ fontSize: "2.8rem" }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* كلمة MONO في المنتصف - تختفي عند عرض المنتجات */}
      {!showProducts && (
        <div style={{
          position: "fixed",
          top: "50%",
          left: "50%",
          transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.15}px, ${mousePosition.y * 0.15}px)`,
          textAlign: "center",
          zIndex: 25,
          transition: "transform 0.15s ease-out",
          pointerEvents: "none"
        }}>
          <h1 style={{
            fontSize: "7rem",
            fontWeight: "900",
            color: "#22c55e",
            margin: 0,
            letterSpacing: "6px",
            textShadow: "0 0 30px rgba(34,197,94,0.8), 0 0 60px rgba(34,197,94,0.5)",
            whiteSpace: "nowrap"
          }}>
            {texts[textIndex]}
          </h1>
          <div style={{
            width: "120px",
            height: "4px",
            background: "linear-gradient(90deg, #22c55e, #4ade80, #22c55e)",
            margin: "25px auto 0",
            borderRadius: "10px"
          }}></div>
        </div>
      )}

      {/* شريط سفلي */}
      {!showProducts && (
        <div style={{
          position: "fixed",
          bottom: "20px",
          left: "50%",
          transform: "translateX(-50%)",
          textAlign: "center",
          color: "rgba(255,255,255,0.8)",
          fontSize: "13px",
          zIndex: 30,
          pointerEvents: "none",
          backgroundColor: "rgba(0,0,0,0.5)",
          padding: "6px 14px",
          borderRadius: "20px",
          whiteSpace: "nowrap"
        }}>
          ✨ اضغط على أي كارد لاختيار المنتج ✨
        </div>
      )}
    </div>
  );
}
